// src/pages/HomePage.js
import React, { useEffect, useState } from "react";
import axios from "axios";
import BlogCard from "../components/BlogCard";

const HomePage = () => {
  const [blogs, setBlogs] = useState([]);
  const [categories, setCategories] = useState([]);
  const [selectedCategory, setSelectedCategory] = useState("all");

  useEffect(() => {
    const fetchData = async () => {
      try {
        const blogsRes = await axios.get("http://localhost:5000/api/blogs");
        const categoriesRes = await axios.get(
          "http://localhost:5000/api/categories"
        );
        setBlogs(blogsRes.data);
        setCategories(categoriesRes.data);
      } catch (error) {
        console.error("Error fetching data:", error);
      }
    };
    fetchData();
  }, []);

  const filteredBlogs =
    selectedCategory === "all"
      ? blogs
      : blogs.filter((blog) => blog.category_id === selectedCategory);

  return (
    <div className="min-h-screen bg-gray-50">
      {/* ===== HERO SECTION (like your 1st image) ===== */}
      <section className="relative bg-gradient-to-r from-blue-600 to-indigo-700 text-white py-20 px-6 md:px-16 text-center">
        <h1 className="text-4xl md:text-5xl font-bold mb-4">
          Welcome to EduBlog
        </h1>
        <p className="max-w-2xl mx-auto text-lg mb-6">
          A platform where education meets creativity. Explore blogs on
          technology, programming, design, and more to enhance your knowledge.
        </p>
        <button className="bg-white text-blue-600 px-6 py-3 rounded-xl font-semibold shadow hover:bg-gray-200 transition">
          Get Started
        </button>
      </section>

      {/* ===== FEATURE SECTION (like your 2nd image) ===== */}
      <section className="py-16 px-6 md:px-16 bg-white">
        <h2 className="text-3xl font-bold text-center mb-10">
          Why Choose EduBlog?
        </h2>
        <div className="grid md:grid-cols-3 gap-8">
          <div className="bg-gray-100 p-6 rounded-2xl shadow hover:shadow-lg transition">
            <h3 className="text-xl font-semibold mb-2">📚 Quality Content</h3>
            <p>
              Get access to well-researched and detailed blogs written to make
              learning simple and effective.
            </p>
          </div>
          <div className="bg-gray-100 p-6 rounded-2xl shadow hover:shadow-lg transition">
            <h3 className="text-xl font-semibold mb-2">⚡ Easy to Understand</h3>
            <p>
              Blogs are written in a student-friendly way with examples,
              diagrams, and step-by-step explanations.
            </p>
          </div>
          <div className="bg-gray-100 p-6 rounded-2xl shadow hover:shadow-lg transition">
            <h3 className="text-xl font-semibold mb-2">🌍 Explore More</h3>
            <p>
              Explore blogs from multiple categories including Technology,
              Education, Business, and more.
            </p>
          </div>
        </div>
      </section>

      {/* ===== BLOG LISTING ===== */}
      <section className="py-12 px-6 md:px-16">
        <h2 className="text-3xl font-bold mb-6 text-center">Latest Blogs</h2>

        {/* Categories */}
        <div className="flex flex-wrap justify-center gap-3 mb-8">
          <button
            onClick={() => setSelectedCategory("all")}
            className={`px-4 py-2 rounded-full ${
              selectedCategory === "all"
                ? "bg-blue-600 text-white"
                : "bg-gray-200 text-gray-700"
            }`}
          >
            All
          </button>
          {categories.map((cat) => (
            <button
              key={cat.id}
              onClick={() => setSelectedCategory(cat.id)}
              className={`px-4 py-2 rounded-full ${
                selectedCategory === cat.id
                  ? "bg-blue-600 text-white"
                  : "bg-gray-200 text-gray-700"
              }`}
            >
              {cat.name}
            </button>
          ))}
        </div>

        {/* Blogs */}
        <div className="grid md:grid-cols-3 gap-8">
          {filteredBlogs.length > 0 ? (
            filteredBlogs.map((blog) => <BlogCard key={blog.id} blog={blog} />)
          ) : (
            <p className="text-center text-gray-500 col-span-3">
              No blogs found in this category.
            </p>
          )}
        </div>
      </section>
    </div>
  );
};

export default HomePage;
